firmware_template.source:
#include "servo_motor.h"
#define SERVO_PIN 13
static Servo _servo;
static int _angle = 90;
void servo_setup() {
  _servo.attach(SERVO_PIN, 500, 2400);
  _servo.write(90);
  Serial.println("[servo] OK pin=13");
}
void servo_loop() {}
void servo_set_angle(int a) {
  _angle = constrain(a, 0, 180);
  _servo.write(_angle);
  Serial.printf("[servo] %d deg\n", _angle);
}
int servo_get_angle() { return _angle; }
void servo_sweep(int from, int to, int d) {
  int step = (to > from) ? 1 : -1;
  for (int i = from; i != to; i += step) {
    _servo.write(i);
    delay(d);
  }
}
